1	import { ChangeDetectionStrategy, Component, Inject } from '@angular/core';
2	import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
3	import { MatSnackBar } from '@angular/material/snack-bar';
4	import { take } from 'rxjs/operators';
5	
6	import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
7	import { faUpload, faFileAlt, faTrash } from '@fortawesome/free-solid-svg-icons';
8	import { MatButtonModule } from '@angular/material/button';
9	import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
10	
11	// Services - you'll need to import/implement these
12	import { itemService } from '../../helpers/services/main.service'; // Adjust path
13	import { HelperService } from '../../helpers/services/helper.service'; // Adjust path
14	
15	@Component({
16	  selector: 'dflow-file-upload-dialog',
17	  standalone: true,
18	  imports: [
19	    FontAwesomeModule,
20	    MatButtonModule,
21	    MatProgressSpinnerModule
22	],
23	  templateUrl: './file-upload-dialog.component.html',
24	  styleUrls: ['./file-upload-dialog.component.scss'],
25	  changeDetection: ChangeDetectionStrategy.OnPush // Add this
26	})
27	export class FileUploadDialogComponent {
28	  faUpload = faUpload;
29	  faFile = faFileAlt;
30	  faTrash = faTrash;
31	  
32	  selectedFiles: File[] = [];
33	  isLoading = false;
34	
35	  constructor(
36	    private _snackBar: MatSnackBar,
37	    public dialogRef: MatDialogRef<FileUploadDialogComponent>,
38	    private itemService: itemService,
39	    private helperService: HelperService,
40	    @Inject(MAT_DIALOG_DATA) public data: { 
41	      itemId: number, 
42	      value: string,
43	      files?: File[]  // Optional pre-selected files
44	    }
45	  ) {
46	    // If files are passed in data, add them
47	    if (this.data?.files) {
48	      this.selectedFiles = [...this.data.files];
49	    }
50	  }
51	
52	  onFileChange(event: any) {
53	    const files = Array.from(event.target.files) as File[];
54	    this.selectedFiles = [...this.selectedFiles, ...files];
55	  }
56	
57	  onDrop(event: DragEvent) {
58	    event.preventDefault();
59	    if (event.dataTransfer?.files) {
60	      const files = Array.from(event.dataTransfer.files);
61	      this.selectedFiles = [...this.selectedFiles, ...files];
62	    }
63	  }
64	
65	  allowDrop(event: DragEvent) {
66	    event.preventDefault();
67	  }
68	
69	  removeFile(index: number) {
70	    this.selectedFiles.splice(index, 1);
71	  }
72	
73	  onCancel() {
74	    this.dialogRef.close();
75	  }
76	
77	  onSave() {
78	    if (this.isLoading) { return; }
79	    
80	    if (!this.selectedFiles.length) {
81	      this._snackBar.open("You need to choose file first!", 'Close', {
82	        duration: 2000,
83	      });
84	      return;
85	    }
86	
87	    const file = this.selectedFiles[0];
88	    let contentType = file.type;
89	    const extension = file.name.split('.').pop().toLowerCase();
90	    let fileName;
91	    
92	    if (extension === 'ai') {
93	      fileName = `${new Date().getTime()}-${file.name.toLowerCase().replace('.ai', '.pdf')}`;
94	      contentType = 'application/pdf';
95	    } else if (['ai', 'pdf'].includes(extension)) {
96	      fileName = `${new Date().getTime()}-${file.name.toLowerCase()}`;
97	    } else {
98	      fileName = 'images-' + `${new Date().getTime()}-${file.name.toLowerCase()}`;
99	    }
100	    
101	    this.isLoading = true;
102	    
103	    this.itemService
104	      .getPreSignedUrl({ fileName, contentType })
105	      .subscribe((res: { signedUrl: string }) => {
106	        const signedUrl = res.signedUrl;
107	        const headers = new Headers({ 
108	          'Content-Type': contentType, 
109	          'x-amz-acl': 'public-read' 
110	        });
111	        
112	        const putConfig = { 
113	          method: 'PUT', 
114	          body: file, 
115	          headers: headers 
116	        };
117	        
118	        fetch(signedUrl, putConfig)
119	          .then(async output => {
120	            if (!this.data.itemId) {
121	              const sharedLink = this.helperService.buildPublicUrl(fileName);
122	              const thumbName = `thumbs-${fileName.replace('images-', '')}`;
123	              const thumbFile = await this.helperService.resizeImage(file, thumbName);
124	              await this.helperService.saveToDigitalOceanAndDB(thumbName, contentType, thumbFile);
125	              const thumbSharedLink = this.helperService.buildPublicUrl(thumbName);
126	              
127	              this.isLoading = false;
128	              return this.dialogRef.close({ sharedLink, thumbSharedLink });
129	            }
130	            
131	            const body = this.data.value === 'rfq'
132	              ? { flag: 'rfq-update', fileName }
133	              : {
134	                  flag: 'item-attachment-create',
135	                  item_num_id_fk: this.data.itemId,
136	                  attachment_type: contentType,
137	                  attachment_display_name: contentType.split("/")[0],
138	                  fileName
139	                };
140	            
141	            this.itemService
142	              .saveTechLink(body, this.data.itemId)
143	              .pipe(take(1))
144	              .subscribe((res: { sharedLink: string }) => {
145	                this.isLoading = false;
146	                this.dialogRef.close(res.sharedLink);
147	              });
148	          })
149	          .catch(error => {
150	            this.isLoading = false;
151	            this._snackBar.open("Upload failed!", 'Close', {
152	              duration: 2000,
153	            });
154	            console.error('Upload error:', error);
155	          });
156	      });
157	  }
158	}

